28	typedef struct {
29	    const char *prompt;
30	    const char *system;
31	    int n_predict;
32	    int ctx_size;
33	    float temperature;
34	    float top_p;
35	    float min_p;
36	    uint64_t seed;
37	    bool dump_tokens;
38	    const char *dump_logits_path;
39	    const char *dump_logprobs_path;
40	    int dump_logprobs_top_k;
41	    const char *perplexity_file_path;
42	    const char *imatrix_dataset_path;
43	    const char *imatrix_output_path;
44	    int imatrix_max_prompts;
45	    int imatrix_max_tokens;
46	    ds4_think_mode think_mode;
47	    bool head_test;
48	    bool first_token_test;
49	    bool metal_graph_test;
50	    bool metal_graph_full_test;
51	    bool metal_graph_prompt_test;
52	} cli_generation_options;
53	
54	typedef struct {
55	    ds4_engine_options engine;
56	    ds4_dist_options *dist;
57	    cli_generation_options gen;
58	    char *prompt_owned;
59	    bool inspect;
60	} cli_config;
61	
62	static volatile sig_atomic_t cli_interrupted;
63	static volatile sig_atomic_t cli_dist_busy;
64	static volatile sig_atomic_t cli_dist_notice_printed;
65	
66	static const char cli_dist_drain_msg[] =
67	    "\nds4: stopping after the distributed cluster finishes the current token/chunk...\n";
68	
69	static void cli_sigint_handler(int sig) {
70	    (void)sig;
71	    cli_interrupted = 1;
72	    if (cli_dist_busy && !cli_dist_notice_printed) {
73	        cli_dist_notice_printed = 1;
74	        ssize_t ignored = write(STDERR_FILENO,
75	                                cli_dist_drain_msg,
76	                                sizeof(cli_dist_drain_msg) - 1u);
77	        (void)ignored;
78	    }
79	}
80	
81	static bool cli_interrupt_requested(void) {
82	    return cli_interrupted != 0;
83	}
84	
85	static void cli_interrupt_clear(void) {
86	    cli_interrupted = 0;
87	    cli_dist_notice_printed = 0;
88	}
89	
90	static bool cli_distributed_coordinator(const cli_config *cfg) {
91	    return cfg && cfg->engine.distributed.role == DS4_DISTRIBUTED_COORDINATOR;
92	}
93	
94	static void cli_dist_busy_set(const cli_config *cfg, bool busy) {
95	    if (!cli_distributed_coordinator(cfg)) return;
96	    cli_dist_busy = busy ? 1 : 0;
97	    if (!busy) cli_dist_notice_printed = 0;
98	}
99	
100	static int cli_wait_distributed_route(const cli_config *cfg, ds4_session *session) {
101	    if (!cli_distributed_coordinator(cfg)) return 0;
102	
103	    char err[256] = {0};
104	    char last[256] = {0};
105	    unsigned ticks = 0;
106	    const struct timespec delay = {0, 250000000L};
107	
108	    for (;;) {
109	        int ready = ds4_session_distributed_route_ready(session, err, sizeof(err));
110	        if (ready > 0) {
111	            if (ticks) fprintf(stderr, "ds4: distributed route ready\n");
112	            return 0;
113	        }
114	        if (ready < 0) {
115	            fprintf(stderr,
116	                    "ds4: distributed route readiness failed: %s\n",
117	                    err[0] ? err : "unknown error");
118	            return 1;
119	        }
120	
121	        const char *why = err[0] ? err : "route incomplete";
122	        if (strcmp(last, why) != 0 || (ticks % 20u) == 0) {
123	            fprintf(stderr, "ds4: waiting for distributed route: %s\n", why);
124	            snprintf(last, sizeof(last), "%s", why);
125	        }
126	        nanosleep(&delay, NULL);
127	        ticks++;
128	    }
129	}
130	
131	static void usage(FILE *fp, const char *topic) {
132	    ds4_help_print(fp, DS4_HELP_DS4, topic);
133	}
134	
135	static int parse_int(const char *s, const char *opt) {
136	    char *end = NULL;
137	    long v = strtol(s, &end, 10);
138	    if (s[0] == '\0' || *end != '\0' || v <= 0 || v > INT32_MAX) {
139	        fprintf(stderr, "ds4: invalid value for %s: %s\n", opt, s);
140	        exit(2);
141	    }
142	    return (int)v;
143	}
144	
145	static uint64_t parse_u64(const char *s, const char *opt) {
146	    char *end = NULL;
147	    unsigned long long v = strtoull(s, &end, 10);
148	    if (s[0] == '\0' || *end != '\0' || v == 0) {
149	        fprintf(stderr, "ds4: invalid value for %s: %s\n", opt, s);
150	        exit(2);
151	    }
152	    return (uint64_t)v;
153	}
154	
155	static float parse_float_range(const char *s, const char *opt, float min, float max) {
156	    char *end = NULL;
157	    float v = strtof(s, &end);
158	    if (s[0] == '\0' || *end != '\0' || !isfinite(v) || v < min || v > max) {
159	        fprintf(stderr, "ds4: invalid value for %s: %s\n", opt, s);
160	        exit(2);
161	    }
162	    return v;
163	}
164	
165	static ds4_backend parse_backend(const char *s) {
166	    if (!strcmp(s, "metal")) return DS4_BACKEND_METAL;
167	#ifdef DS4_ROCM_BUILD
168	    if (!strcmp(s, "rocm")) return DS4_BACKEND_CUDA;
169	#else
170	    if (!strcmp(s, "cuda")) return DS4_BACKEND_CUDA;
171	#endif
172	    if (!strcmp(s, "cpu")) return DS4_BACKEND_CPU;
173	    fprintf(stderr, "ds4: invalid backend: %s\n", s);
174	#ifdef DS4_ROCM_BUILD
175	    fprintf(stderr, "ds4: valid backends are: metal, rocm, cpu\n");
176	#else
177	    fprintf(stderr, "ds4: valid backends are: metal, cuda, cpu\n");
178	#endif
179	    exit(2);
180	}
181	
182	static ds4_backend default_backend(void) {
183	#ifdef DS4_NO_GPU
184	    return DS4_BACKEND_CPU;
185	#elif defined(__APPLE__)
186	    return DS4_BACKEND_METAL;
187	#else
188	    return DS4_BACKEND_CUDA;
189	#endif
190	}
191	
192	static void log_context_memory(ds4_backend backend,
193	                               int         ctx_size,
194	                               uint32_t    prefill_chunk) {
195	    ds4_context_memory m =
196	        ds4_context_memory_estimate_with_prefill(backend,
197	                                                 ctx_size,
198	                                                 prefill_chunk);
199	    fprintf(stderr,
200	            "ds4: context buffers %.2f MiB (ctx=%d, backend=%s, prefill_chunk=%u, raw_kv_rows=%u, compressed_kv_rows=%u)\n",
201	            (double)m.total_bytes / (1024.0 * 1024.0),
202	            ctx_size,
203	            ds4_backend_name(backend),
204	            m.prefill_cap,
205	            m.raw_cap,
206	            m.comp_cap);
207	}
208	
209	static ds4_think_mode cli_effective_think_mode(const cli_generation_options *gen) {
210	    return ds4_think_mode_for_context(gen->think_mode, gen->ctx_size);
211	}
212	
213	static bool cli_think_max_downgraded(const cli_generation_options *gen) {
214	    return gen->think_mode == DS4_THINK_MAX &&
215	           cli_effective_think_mode(gen) != DS4_THINK_MAX;
216	}
217	
218	static void cli_warn_think_max_downgraded(const cli_generation_options *gen, const char *name) {
219	    if (!cli_think_max_downgraded(gen)) return;
220	    ds4_log(stderr,
221	        DS4_LOG_WARNING,
222	        "ds4: warning: %s needs --ctx >= %u; ctx=%d uses normal thinking instead\n",
223	        name,
224	        ds4_think_max_min_context(),
225	        gen->ctx_size);
226	}
227	
